def read_json(path: Path) -> dict:
    if not path.exists():
        return {}
    return json.loads(path.read_text(encoding="utf-8"))


METADATA = read_json(METADATA_PATH)
MODEL_CONFIG = read_json(MODEL_CONFIG_PATH)
METRICS = METADATA.get("metrics", {}) or MODEL_CONFIG.get("test_metrics", {})
FEATURES = METADATA.get("features") or MODEL_CONFIG.get("features", [])
FEATURE_COUNT = int(METADATA.get("feature_count") or MODEL_CONFIG.get("feature_count") or len(FEATURES) or 68)
THRESHOLD = float(METADATA.get("threshold") or MODEL_CONFIG.get("threshold") or 0.58)
CATEGORICAL_FEATURES = METADATA.get("categorical_features", ["location"])
TEST_PERIOD = (METRICS.get("test_start_date"), METRICS.get("test_end_date"))


def fmt_int(value: object) -> str:
    try:
        return f"{int(value):,}"
    except (TypeError, ValueError):
        return "n/a"


FEATURE_GROUPS: list[tuple[str, tuple[str, ...]]] = [
    ("Missingness memory", ("_missing_hybrid",)),
    ("Lag / 24h dynamics", ("_24h_diff", "_yest")),
    ("Climate zones & bins", ("rainfall_zone_", "_bin")),
    ("Wind vectors", ("wind_dir", "wind_gust_dir", "wind_shift")),
    ("Moisture & stability", ("dewpoint", "moisture_stability", "humidity_temp", "pressure_humidity", "cloud_humidity", "humidity_rising", "warming_day", "temp_range", "temp_day_diff", "humidity_day_diff", "pressure_day_diff")),
    ("Station & calendar", ("location", "lat", "lon", "elevation", "month", "day", "year", "year_cycle")),
    ("Raw weather observations", ("min_temp", "max_temp", "rainfall", "evaporation", "sunshine", "temp_9am", "temp_3pm", "humidity_9am", "humidity_3pm", "pressure_9am", "pressure_3pm", "cloud_9am", "cloud_3pm", "rain_today", "wind_gust_speed", "wind_speed")),
]


def group_features(features: list[str]) -> pd.DataFrame:
    rows: list[tuple[str, str]] = []
    assigned: set[str] = set()
    for group, needles in FEATURE_GROUPS:
        for feature in features:
            if feature in assigned:
                continue
            if any(needle in feature for needle in needles):
                rows.append((group, feature))
                assigned.add(feature)
    for feature in features:
        if feature not in assigned:
            rows.append(("Other", feature))
    return pd.DataFrame(rows, columns=["Group", "Feature"])


