def tool_chips(items: Iterable[tuple[str, str, str]]) -> None:
    chips = ["<div class='chip-row'>"]
    for name, mark, color in items:
        logo = TOOL_LOGOS.get(name)
        if logo:
            badge = f"<span class='logo'><img src='{logo}' alt='{escape(name)} logo'/></span>"
        else:
            badge = f"<span style='--c:{escape(color)}'>{escape(mark)}</span>"
        chips.append(f"<div class='tool-chip'>{badge}{escape(name)}</div>")
    chips.append("</div>")
    html("".join(chips))


def logo_badge(name: str, color: str, mark: str | None = None) -> str:
    logo = TOOL_LOGOS.get(name)
    if logo:
        return f"<span class='logo-badge'><img src='{logo}' alt='{escape(name)} logo'/></span>"
    initials = mark or "".join(word[0] for word in name.split()[:2]).upper()
    return f"<span class='logo-badge initials' style='--c:{escape(color)}'>{escape(initials)}</span>"


def metric_cards(items: list[tuple[str, str, str]], columns: int = 4) -> None:
    cols = st.columns(columns, gap="medium")
    for index, (label, value, note) in enumerate(items):
        with cols[index % columns]:
            html(
                f"""
                <div class="metric-card">
                  <div class="metric-label">{escape(label)}</div>
                  <div class="metric-value">{escape(value)}</div>
                  <div class="metric-note">{escape(note)}</div>
                </div>
                """
            )


